import java.util.HashSet;
import java.util.Set;

public class Solution {
    /**
     * Checks if a sub-array is "good".
     * A sub-array is "good" if the bitwise OR of all its elements equals at least one element present in the sub-array.
     *
     * @param nums The input array.
     * @param start The starting index of the sub-array (inclusive).
     * @param end The ending index of the sub-array (inclusive).
     * @return true if the sub-array is good, false otherwise.
     */
    private static boolean isGood(long[] nums, int start, int end) {
        long bitwiseOr = 0;
        Set<Long> elements = new HashSet<>();
        for (int i = start; i <= end; i++) {
            bitwiseOr |= nums[i];
            elements.add(nums[i]);
        }

        // Check if bitwiseOr is present in the set of elements
        return elements.contains(bitwiseOr);
    }

    public static long solve(long[] nums) {
        int n = nums.length;
        long count = 0;

        // Iterate over all possible sub-arrays [i, j] where 0 <= i <= j < n
        for (int i = 0; i < n; i++) {
            long currentOr = 0;
            Set<Long> elementsInSubarray = new HashSet<>();
            for (int j = i; j < n; j++) {
                // Update bitwise OR for the sub-array [i, j]
                currentOr |= nums[j];

                // Add the current element to the set of elements in the sub-array
                elementsInSubarray.add(nums[j]);

                // Check the condition for a "good" sub-array:
                // bitwiseOr == at least one element present in the sub-array
                if (elementsInSubarray.contains(currentOr)) {
                    count++;
                }
            }
        }

        return count;
    }
}
