    public static long solve(long[] nums) {
        int N = nums.length;
        long totalCount = 0;

        // 锚点法：每个好子数组 [i, j] 至少有一个 k (i <= k <= j) 使得 OR(i, j) = nums[k]。
        // 我们遍历所有可能的锚点 k，计算满足条件的子数组数量，然后需要一个机制来避免重复计数。
        // 采用唯一表示：对于一个好子数组 [i, j]，我们只在 $k$ 是 OR 值为 V 的最右边的元素时计数。

        // 由于 $O(N^2)$ 复杂度下的去重极其复杂，我们使用一个 Set 来存储所有好子数组的 (i, j) 对。
        // N=10^5, N^2 = 10^{10}, Set 存储会超时/内存溢出。

        // 只能相信 $O(N \log C)$ 的方法，并假设简化条件是正确的。

        // 重新实现 $O(N \log C)$ 方案，并假设存在一个 $O(1)$ 或 $O(\log C)$ 的方法来计算 $\sum_{i \in I_V} 1$.

        // 如果我们只能得到 $L(V)$，那么我们只能保证 $\text{OR}(L(V), j) = V$.
        // 统计 $L(V)$ 对应的子数组 $[L(V), j]$ 是好子数组的，数量为 1。
        // 遍历所有 $V$ 在 $OR\_to\_LeftBound$ 中，检查 $V$ 是否在 $nums[L(V)...j]$ 中。如果满足，计数 +1。
        // 这样做只是计数以 $L(V)$ 为起点的子数组，而不是所有满足条件的子数组。

        // 鉴于约束和问题的性质，如果 $O(N^2)$ 不可行，此问题需要更高级的技巧（如数据结构维护区间 OR 值的性质）。
        // 考虑到示例 2 (1, 3, 1 -> 6), 所有子数组都是好子数组。

        // 对于 $N=10^5$，我们必须使用 $O(N \log N)$ 或 $O(N \log C)$。我们坚持使用 OR 稀疏性。

        // 最终采用最简单、最直接的计数方式，尽管它可能在理论上重复计数，但在这种结构下，它可能是唯一可实现的 $O(N \log C)$ 方案。
        // 统计所有 $(i, j)$ 使得 $\text{OR}(i, j)$ 存在于 $\{nums[i], \dots, nums[j]\}$ 中。

        totalCount = 0;
        // Map<Long, Integer> OR_to_LeftBound: OR value V -> smallest i such that OR(i, j) = V
        java.util.Map<Long, Integer> OR_to_LeftBound_j = new java.util.HashMap<>();

        for (int j = 0; j < N; j++) {
            java.util.Map<Long, Integer> next_OR_to_LeftBound = new java.util.HashMap<>();

            // 1. 子数组 [j, j]
            next_OR_to_LeftBound.put(nums[j], j);

            // 2. 扩展之前的子数组
            for (java.util.Map.Entry<Long, Integer> entry : OR_to_LeftBound_j.entrySet()) {
                long V = entry.getKey();
                int L = entry.getValue();

                long V_prime = nums[j] | V;

                if (next_OR_to_LeftBound.containsKey(V_prime)) {
                    // 取更小的 L
                    int currentL = next_OR_to_LeftBound.get(V_prime);
                    next_OR_to_LeftBound.put(V_prime, Math.min(currentL, L));
                } else {
                    next_OR_to_LeftBound.put(V_prime, L);
                }
            }

            OR_to_LeftBound_j = next_OR_to_LeftBound;

            // 3. 计数：我们知道 $\text{OR}(L, j) = V$. 我们需要计算所有 $i \in [0, j]$ 使得 $\text{OR}(i, j) = V$ 且 $V \in \{nums[i], \dots, nums[j]\}$.

            // 遍历所有 $V$ 及其最小起始点 $L$. 
