import java.util.HashSet;
import java.util.Set;

class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        long count = 0;

        // Iterate over all possible starting indices i
        for (int i = 0; i < n; i++) {
            long currentOr = 0;
            // Keep track of the elements encountered in the current subarray nums[i...j]
            Set<Long> presentElements = new HashSet<>();

            // Iterate over all possible ending indices j (j >= i)
            for (int j = i; j < n; j++) {
                long currentElement = nums[j];

                // Update the bitwise OR for the subarray nums[i...j]
                currentOr |= currentElement;

                // Add the current element to the set of present elements
                presentElements.add(currentElement);

                // Check the condition:
                // The bitwise OR of all elements must equal at least one element present in the subarray.

                boolean conditionMet = false;
                // Iterate through all elements present in nums[i...j]
                for (long element : presentElements) {
                    if (currentOr == element) {
                        conditionMet = true;
                        break;
                    }
                }

                if (conditionMet) {
                    count++;
                }
            }
        }

        return count;
    }
}
